#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,dp[302][302],a[302];
    cin>>n;
    memset(dp,127,sizeof(dp));
    for(int i=1;i<=n;i++){
        cin>>a[i];
        dp[i][i]=1;
    }
    for(int len=2;len<=n;len++)
        for(int l=1;l+len-1<=n;l++){
            int r=l+len-1;
            for(int k=l;k<r;k++)dp[l][r]=min(dp[l][r],dp[l][k]+dp[k+1][r]-(a[l]==a[r]));
        }
    cout<<dp[1][n];
    return 0;
}
